+    AttestationQuote {
+        platform: TeePlatform::ArmCca,
+        measurement: MeasurementDigest {
+            algorithm: MeasurementAlgorithm::Sha256,
+            digest_hex: digest_hex(0x44, 32),
+        },
+        quote_age_secs: 5,
+        trust_root_id: trust_root_id.to_string(),
+        revocation_observations: rev,
+    }
